// ─── HERO CAROUSEL ──────────────────────────────────────────
const HeroCarousel = ({ onCoverClick }) => {
  const [active, setActive] = useState(0);
  const total = CAROUSEL_COVERS.length;

  useEffect(() => {
    const timer = setInterval(() => setActive(p => (p + 1) % total), 3500);
    return () => clearInterval(timer);
  }, [total]);

  return (
    <div style={{ position: "relative", width: "100%", height: "100%", display: "flex", alignItems: "center", justifyContent: "center" }}>
      {CAROUSEL_COVERS.map((cover, i) => {
        const offset = ((i - active + total) % total);
        const isCenter = offset === 0;
        const isR1 = offset === 1, isR2 = offset === 2;
        const isL1 = offset === total - 1, isL2 = offset === total - 2;
        const vis = isCenter || isR1 || isR2 || isL1 || isL2;

        let x=0, sc=0.65, op=0, z=0, ry=0;
        if (isCenter) { x=0; sc=1; op=1; z=10; ry=0; }
        if (isR1) { x=155; sc=0.78; op=0.5; z=5; ry=-12; }
        if (isR2) { x=260; sc=0.62; op=0.15; z=2; ry=-18; }
        if (isL1) { x=-155; sc=0.78; op=0.5; z=5; ry=12; }
        if (isL2) { x=-260; sc=0.62; op=0.15; z=2; ry=18; }

        return (
          <div key={i} onClick={() => { setActive(i); if (isCenter && onCoverClick) onCoverClick(cover.id); }}
            style={{
              position: "absolute", width: 210, height: 296, cursor: isCenter ? "pointer" : "default",
              transform: `translateX(${x}px) scale(${sc}) perspective(900px) rotateY(${ry}deg)`,
              opacity: vis ? op : 0, zIndex: z,
              transition: "all 0.7s cubic-bezier(0.4, 0, 0.2, 1)",
            }}>
            <div style={{
              width: "100%", height: "100%", borderRadius: 8, overflow: "hidden", position: "relative",
              border: `1px solid ${isCenter ? cover.color + "50" : cover.color + "20"}`,
              boxShadow: isCenter ? `0 12px 48px rgba(0,0,0,0.5), 0 0 28px ${cover.color}12` : `0 4px 20px rgba(0,0,0,0.4)`,
            }}>
              <img src={cover.img} alt={cover.title} style={{
                width: "100%", height: "100%", objectFit: "cover", objectPosition: "top center",
                display: "block", imageRendering: "auto", WebkitBackfaceVisibility: "hidden",
              }}/>
              {isCenter && (
                <div style={{ position: "absolute", bottom: 0, left: 0, right: 0, padding: "24px 14px 10px",
                  background: "linear-gradient(transparent, rgba(10,14,20,0.9) 50%)" }}>
                  <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 13, fontWeight: 700,
                    color: cover.color, textAlign: "center", letterSpacing: "0.02em", textTransform: "uppercase", whiteSpace: "pre-line" }}>
                    {cover.title}
                  </div>
                </div>
              )}
            </div>
          </div>
        );
      })}
      <div style={{ position: "absolute", bottom: -4, left: "50%", transform: "translateX(-50%)", display: "flex", gap: 6 }}>
        {CAROUSEL_COVERS.map((c, i) => (
          <div key={i} onClick={() => setActive(i)} style={{
            width: active === i ? 18 : 6, height: 6, borderRadius: 3, cursor: "pointer",
            background: active === i ? CAROUSEL_COVERS[active].color : C.text4,
            transition: "all 0.3s ease",
            boxShadow: active === i ? `0 0 8px ${CAROUSEL_COVERS[active].color}50` : "none",
          }}/>
        ))}
      </div>
    </div>
  );
};

