// ─── GRANULAR TOOLS CAROUSEL ─────────────────────────────────
const GranularCarousel = () => {
  const scrollRef = useRef(null);
  const [paused, setPaused] = useState(false);

  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    let animId;
    const speed = 0.5;
    const tick = () => {
      if (!paused && el) {
        el.scrollLeft += speed;
        // Loop: when we've scrolled past the original set, reset
        if (el.scrollLeft >= el.scrollWidth / 2) {
          el.scrollLeft = 0;
        }
      }
      animId = requestAnimationFrame(tick);
    };
    animId = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(animId);
  }, [paused]);

  // Double the items for infinite scroll illusion
  const items = [...GRANULAR_TOOLS, ...GRANULAR_TOOLS];

  return (
    <div style={{ position: "relative" }}
      onMouseEnter={() => setPaused(true)} onMouseLeave={() => setPaused(false)}>
      {/* Fade edges */}
      <div style={{ position: "absolute", top: 0, left: 0, bottom: 0, width: 60, zIndex: 2,
        background: "linear-gradient(90deg, #0A0E14, transparent)", pointerEvents: "none" }}/>
      <div style={{ position: "absolute", top: 0, right: 0, bottom: 0, width: 60, zIndex: 2,
        background: "linear-gradient(270deg, #0A0E14, transparent)", pointerEvents: "none" }}/>

      <div ref={scrollRef} style={{
        display: "flex", gap: 20, overflowX: "auto", scrollBehavior: "auto",
        paddingBottom: 4, msOverflowStyle: "none", scrollbarWidth: "none",
      }}>
        <style>{`.granular-scroll::-webkit-scrollbar { display: none; }`}</style>
        {items.map((tool, i) => {
          const [hov, setHov] = useState(false);
          return (
            <div key={`${tool.id}-${i}`}
              onMouseEnter={() => setHov(true)} onMouseLeave={() => setHov(false)}
              style={{
                flexShrink: 0, width: 340, padding: "22px 24px", borderRadius: 14, position: "relative", overflow: "hidden",
                background: hov
                  ? "linear-gradient(160deg, rgba(255,255,255,0.07), rgba(255,255,255,0.025) 40%, rgba(255,255,255,0.04))"
                  : "linear-gradient(160deg, rgba(255,255,255,0.04), rgba(255,255,255,0.015) 40%, rgba(255,255,255,0.03))",
                border: hov ? `1px solid ${tool.accent}40` : "1px solid rgba(255,255,255,0.08)",
                boxShadow: hov
                  ? `0 0 30px ${tool.accent}12, 0 8px 32px rgba(0,0,0,0.3), inset 0 1px 0 rgba(255,255,255,0.06)`
                  : "0 4px 20px rgba(0,0,0,0.2), inset 0 1px 0 rgba(255,255,255,0.04)",
                backdropFilter: "blur(16px)",
                transition: "all 0.35s ease", cursor: "pointer",
                display: "flex", flexDirection: "column",
              }}>
              <DiagonalShine />
              {/* Top accent */}
              <div style={{ position: "absolute", top: 0, left: "10%", width: "80%", height: 1.5,
                background: `linear-gradient(90deg, transparent, ${tool.accent}${hov ? "50" : "20"}, transparent)`,
                transition: "all 0.35s ease" }}/>

              {/* Capital tag + FREE */}
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                  <div style={{ width: 6, height: 6, borderRadius: "50%", background: tool.accent }}/>
                  <span style={{ fontSize: 9, fontWeight: 700, letterSpacing: "0.1em", textTransform: "uppercase",
                    color: tool.accent }}>{tool.capital}</span>
                </div>
                <span style={{ padding: "3px 8px", borderRadius: 5, background: `${C.green}18`,
                  border: `1px solid ${C.green}40`, fontSize: 9, fontWeight: 800,
                  letterSpacing: "0.12em", color: C.green }}>FREE</span>
              </div>

              {/* Title */}
              <h4 style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 22, fontWeight: 600,
                color: C.text1, margin: "0 0 3px", lineHeight: 1.15 }}>{tool.title}</h4>
              <span style={{ fontSize: 10, fontWeight: 600, color: tool.accent, letterSpacing: "0.06em",
                textTransform: "uppercase", marginBottom: 10 }}>{tool.subtitle}</span>

              {/* One-liner */}
              <p style={{ fontSize: 12.5, color: C.text2, lineHeight: 1.55, margin: "0 0 14px", flex: 1 }}>{tool.oneLiner}</p>

              {/* Cover preview */}
              {tool.img && (
                <div style={{ display: "flex", justifyContent: "center", marginBottom: 14 }}>
                  <div style={{ borderRadius: 6, overflow: "hidden", width: 140, height: 197,
                    border: `1px solid ${tool.accent}18`,
                    boxShadow: `0 3px 14px rgba(0,0,0,0.25), 0 0 8px ${tool.accent}06` }}>
                    <img src={tool.img} alt={tool.title} style={{
                      width: "100%", height: "100%", objectFit: "cover", objectPosition: "top center",
                      display: "block", imageRendering: "auto",
                      transform: hov ? "scale(1.02)" : "scale(1)", transition: "transform 0.5s ease",
                    }}/>
                  </div>
                </div>
              )}

              {/* Meta + CTA */}
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
                <span style={{ fontSize: 10, color: C.text3 }}>{tool.duration}</span>
                <GoldBtn href={`/tools/${tool.id}`} color={tool.accent}>Start</GoldBtn>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};


// ─── DEEP-DIVE COVER CYCLER ────────────────────────────────
const DeepDiveCycler = () => {
  const [active, setActive] = useState(0);
  const total = CAPITAL_DEEP_DIVES.length;

  useEffect(() => {
    const timer = setInterval(() => setActive(p => (p + 1) % total), 3000);
    return () => clearInterval(timer);
  }, [total]);

  return (
    <div style={{ position: "relative", width: 200, height: 282 }}>
      {CAPITAL_DEEP_DIVES.map((dd, i) => {
        const isCurrent = i === active;
        return (
          <div key={dd.id} style={{
            position: "absolute", top: 0, left: 0, width: 200, height: 282,
            borderRadius: 10, overflow: "hidden",
            border: `1px solid ${isCurrent ? dd.accent + "40" : dd.accent + "15"}`,
            boxShadow: isCurrent
              ? `0 8px 32px rgba(0,0,0,0.35), 0 0 20px ${dd.accent}12`
              : `0 4px 16px rgba(0,0,0,0.2)`,
            opacity: isCurrent ? 1 : 0,
            transform: isCurrent ? "scale(1)" : "scale(0.96)",
            transition: "all 0.6s cubic-bezier(0.4, 0, 0.2, 1)",
            zIndex: isCurrent ? 2 : 1,
          }}>
            <img src={dd.cover} alt={dd.title} style={{
              width: "100%", height: "100%", objectFit: "cover",
              objectPosition: "top center", display: "block",
            }}/>
            <div style={{
              position: "absolute", bottom: 0, left: 0, right: 0,
              padding: "28px 12px 10px",
              background: "linear-gradient(transparent, rgba(10,14,20,0.92) 50%)",
            }}>
              <div style={{ fontFamily: "'Cormorant Garamond', serif", fontSize: 13, fontWeight: 700,
                color: dd.accent, textAlign: "center", letterSpacing: "0.02em", textTransform: "uppercase" }}>
                {dd.capital}<br/>Deep-Dive
              </div>
            </div>
          </div>
        );
      })}
      {/* dots */}
      <div style={{ position: "absolute", bottom: -16, left: "50%", transform: "translateX(-50%)",
        display: "flex", gap: 6, zIndex: 5 }}>
        {CAPITAL_DEEP_DIVES.map((dd, i) => (
          <div key={i} onClick={() => setActive(i)} style={{
            width: active === i ? 16 : 5, height: 5, borderRadius: 3, cursor: "pointer",
            background: active === i ? dd.accent : C.text4,
            transition: "all 0.3s ease",
          }}/>
        ))}
      </div>
    </div>
  );
};

